export const 佩帶符三 = (bi) => {
    const u = bi.u;
    const X = (x) => x;
    const Z = (z) => z + 0.5;
    const 線 = (書, 寬 = 0.55) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    // 山匡：左右外弧＋中柱＋橫貫（兩端出頭下撇）
    線(p => p.M(X(-9.2), Z(1.0))
        .C(X(-8.4), Z(5.0), X(-8.3), Z(9.0), X(-9.0), Z(12.8))
        .C(X(-9.4), Z(14.2), X(-10.2), Z(15.4), X(-11.2), Z(16.2)), 0.6);
    線(p => p.M(X(0.0), Z(1.0)).L(X(-0.1), Z(13.2)), 0.6);
    線(p => p.M(X(8.6), Z(2.0))
        .C(X(7.9), Z(5.8), X(7.9), Z(9.4), X(8.6), Z(12.6))
        .C(X(9.0), Z(14.0), X(9.6), Z(15.2), X(10.4), Z(15.8)), 0.6);
    線(p => p.M(X(-9.0), Z(13.3)).L(X(8.8), Z(13.1)), 0.6);
    // 中段雙弧（左皿曲・右仰弧）
    線(p => p.M(X(-8.6), Z(17.6)).C(X(-5.0), Z(19.2), X(-1.5), Z(19.0), X(1.8), Z(17.4)));
    線(p => p.M(X(2.6), Z(20.0)).C(X(5.4), Z(19.0), X(7.4), Z(17.8), X(8.6), Z(16.4)));
    // 目匣：左欄・中柱・二桁（右欄即長垂之右柱）
    線(p => p.M(X(-8.0), Z(17.8))
        .C(X(-8.4), Z(21.5), X(-8.4), Z(25.0), X(-8.0), Z(28.4)), 0.6);
    線(p => p.M(X(-4.0), Z(19.2)).L(X(-4.1), Z(29.0)), 0.55);
    線(p => p.M(X(-7.9), Z(23.5)).C(X(-5.0), Z(23.9), X(-2.0), Z(23.8), X(0.6), Z(23.3)));
    線(p => p.M(X(-7.9), Z(28.2)).C(X(-5.0), Z(29.2), X(-2.0), Z(29.1), X(0.6), Z(28.3)));
    // 右下乁鉤＋右柱
    線(p => p.M(X(1.6), Z(28.4)).C(X(3.6), Z(30.0), X(6.4), Z(30.2), X(9.4), Z(28.4)));
    線(p => p.M(X(6.6), Z(30.4))
        .C(X(6.4), Z(35.5), X(6.0), Z(40.5), X(5.2), Z(44.5))
        .C(X(4.9), Z(45.9), X(4.5), Z(46.9), X(4.0), Z(47.6)), 0.6);
    // 三足：左欄長垂（末左鉤）・中撇・右內柱垂
    線(p => p.M(X(-8.0), Z(28.4))
        .L(X(-8.2), Z(40.0))
        .C(X(-8.3), Z(43.5), X(-8.6), Z(45.8), X(-9.4), Z(47.0)), 0.6);
    線(p => p.M(X(-0.6), Z(33.0))
        .C(X(-3.0), Z(37.5), X(-5.6), Z(42.5), X(-8.0), Z(47.2)), 0.6);
    線(p => p.M(X(0.5), Z(20.2))
        .L(X(0.4), Z(30.0))
        .C(X(0.5), Z(36.0), X(0.9), Z(42.0), X(1.8), Z(47.8)), 0.55);
};
